#include <iostream>
#include <cmath>

struct Vec3 {
    float x, y, z;

    // دوال داخل البنية تُسمى methods أو member functions
    // يمكنها الوصول المباشر للحقول بدون معامل
    float length() const {
        return std::sqrt(x * x + y * y + z * z);
    }

    // normalize يُعدّل البنية نفسها — لذلك لا يكون const
    void normalize() {
        float len = length();
        if (len > 0.0f) {
            x /= len;
            y /= len;
            z /= len;
        }
    }
};

int main() {
    Vec3 dir{3.0f, 0.0f, 4.0f};
    std::cout << "الطول: " << dir.length() << '\n'; // 5

    dir.normalize();
    std::cout << "بعد التطبيع: " << dir.x << "," << dir.y << "," << dir.z << '\n';
    // 0.6, 0, 0.8

    return 0;
}

#include <iostream>
#include <string>

struct Player {
    std::string name;
    int health;
    int score;

    // المُنشئ: دالة تُستدعى تلقائيًا عند إنشاء البنية
    // يُضمن أن البنية دائمًا في حالة صالحة
    Player(const std::string& n, int h, int s)
        : name(n), health(h), score(s) {}

    void takeDamage(int dmg) {
        health -= dmg;
        if (health < 0) health = 0;
    }

    bool isAlive() const { return health > 0; }
};

int main() {
    // المُنشئ يُستدعى تلقائيًا — لا يمكن ترك الحقول فارغة
    Player hero{"Ali", 100, 0};
    hero.takeDamage(30);

    std::cout << hero.name << ": " << hero.health << " HP" << '\n';

    return 0;
}

